func:
const incoming = msg.payload;
msg.payload = {
    deviceId: incoming.deviceId || 'ESP32_01',
    bpm: Number(incoming.bpm),
    spo2: Number(incoming.spo2),
    bodyTemp: Number(incoming.bodyTemp),
    timestamp: new Date().toISOString()
};
return msg;

const savedTelemetry = msg.payload;
// Preserve the newly created document details for later steps
msg.vitalsContext = savedTelemetry;

// Setup query payload matching the incoming device configuration targets
msg.payload = { deviceId: savedTelemetry.deviceId || 'ESP32_01' };
return msg;

const groqKey = process.env.GROQ_API_KEY;
const currentVitals = msg.vitalsContext;

// Capture fallback defaults if a specific config layout sheet isn't assigned yet inside Atlas
const cfg = msg.payload || {
    minBPM: 60, maxBPM: 100, minSpO2: 95, maxSpO2: 100, minTemp: 36.0, maxTemp: 37.5
};
msg.configContext = cfg;

msg.headers = { 
    'Authorization': 'Bearer ' + groqKey, 
    'Content-Type': 'application/json' 
};

msg.payload = {
    model: 'llama-3.1-8b-instant',
    messages: [
        { 
            role: 'system', 
            content: 'You are an advanced medical telemetry monitor analyst AI. You must evaluate current data against the provided target threshold ranges. You MUST respond exactly in this structural format with no extra conversational text:\nStatus: [Normal OR Warning <parameter 1 is increasing..> OR Alert <parameter 1 has crossed threshold>]\nRemark: [Your observation, e.g., Signs of body temp increasing. Increased from [X] to [Y] and is increasing now.]'
        },
        {
            role: 'user',
            content: `Evaluate this medical context:\n\nCURRENT TELEMETRY RECORD:\n- Pulse Rate: ${currentVitals.bpm} BPM\n- Blood Oxygen (SpO2): ${currentVitals.spo2}%\n- Body Temperature: ${currentVitals.bodyTemp}°C\n\nTARGET DATABASE SAFE RANGE THRESHOLDS:\n- Pulse Limits: ${cfg.minBPM} to ${cfg.maxBPM} BPM\n- Oxygen Target: Above ${cfg.minSpO2}%\n- Temperature Limits: ${cfg.minTemp} to ${cfg.maxTemp}°C` 
        }
    ]
};

return msg;

const aiAnalysisText = msg.payload?.choices?.[0]?.message?.content || 'Status: Warning\nRemark: AI Analysis engine parsing failure.';
const lastReading = msg.vitalsContext;
const cfg = msg.configContext;

let alerts = [];
if (lastReading.bpm < cfg.minBPM || lastReading.bpm > cfg.maxBPM) alerts.push(`Pulse Breach: ${lastReading.bpm} BPM`);
if (lastReading.spo2 < cfg.minSpO2) alerts.push(`Hypoxia Breach: ${lastReading.spo2}%`);
if (lastReading.bodyTemp < cfg.minTemp || lastReading.bodyTemp > cfg.maxTemp) alerts.push(`Temp Breach: ${lastReading.bodyTemp}°C`);

// If AI generated a critical status or the math check flags a breach, trigger emergency alert routing
if (alerts.length > 0 || aiAnalysisText.includes('Alert') || aiAnalysisText.includes('Warning')) {
    msg.to = "your-alert-inbox@gmail.com";
    msg.topic = "⚠️ HEALTH ALERT SYSTÈM: " + lastReading.deviceId;
    msg.payload = `AI Clinical Assessment:\n${aiAnalysisText}\n\nRaw Mathematical Breaches Found:\n${alerts.length > 0 ? alerts.join('\n') : 'None parsed by strict bounds.'}`;
    return msg;
}

return null;
